#!/usr/bin/env python3
"""
Convert TR-808 drum samples from Compulidian format to Motorik samples.h.

Reads Bd2550.h, Sd0010.h, Ch.h from the Compulidian 808 sample set.
- Parses C int16_t arrays
- Resamples from 44100 Hz to 48000 Hz using linear interpolation
- Scales from +/-32767 to +/-2047 (AudioOut range)
- Trims kick to 250ms
- Outputs samples.h in Motorik namespace format
"""

import os
import re

SAMPLES_DIR = "/Users/pjoe/Experimenten/Compulidian/include/audio/808samples"
SRC_RATE = 44100
DST_RATE = 48000
SCALE_FACTOR = 2047.0 / 32767.0
KICK_TRIM_MS = 250


def parse_c_array(filepath):
    """Parse a C header file containing a const int16_t array and return samples as list of ints."""
    with open(filepath, "r") as f:
        content = f.read()

    # Find the array name and content
    # Format: const int16_t Name[] = { values };
    match = re.search(r"const\s+int16_t\s+(\w+)\s*\[\s*\]\s*=\s*\{([^}]+)\}", content)
    if not match:
        raise ValueError(f"Could not parse array from {filepath}")

    name = match.group(1)
    values_str = match.group(2)

    # Parse comma-separated integers
    values = []
    for token in values_str.split(","):
        token = token.strip()
        if token:
            values.append(int(token))

    return name, values


def resample_linear(samples, src_rate, dst_rate):
    """Resample using linear interpolation from src_rate to dst_rate."""
    src_len = len(samples)
    dst_len = int(src_len * dst_rate / src_rate)
    result = []

    for i in range(dst_len):
        src_pos = i * src_len / dst_len
        idx = int(src_pos)
        frac = src_pos - idx

        if idx + 1 < src_len:
            s0 = samples[idx]
            s1 = samples[idx + 1]
            val = s0 + (s1 - s0) * frac
        else:
            val = samples[min(idx, src_len - 1)]

        result.append(int(round(val)))

    return result


def scale_to_audioout(samples):
    """Scale from +/-32767 range to +/-2047 range."""
    return [int(round(s * SCALE_FACTOR)) for s in samples]


def trim_samples(samples, rate, duration_ms):
    """Trim samples to duration_ms milliseconds at given sample rate."""
    max_samples = int(rate * duration_ms / 1000)
    if len(samples) > max_samples:
        return samples[:max_samples]
    return samples


def write_header(kick, snare, hihat, output_path):
    """Write samples.h in Motorik format."""
    with open(output_path, "w") as f:
        f.write("#ifndef SAMPLES_H\n")
        f.write("#define SAMPLES_H\n\n")
        f.write("#include <cstdint>\n\n")
        f.write("// TR-808 drum samples for Motorik card\n")
        f.write("// Original: 44100Hz, resampled to 48000Hz, scaled to +/-2047\n")
        f.write("// Generated by convert_samples.py\n\n")
        f.write("namespace Samples {\n\n")

        f.write("constexpr uint32_t KICK_SAMPLES = {};\n".format(len(kick)))
        f.write("const int16_t kick[KICK_SAMPLES] = {\n    ")
        for i, s in enumerate(kick):
            if i > 0 and i % 8 == 0:
                f.write("\n    ")
            f.write("{:5d}, ".format(s))
        f.write("\n};\n\n")

        f.write("constexpr uint32_t SNARE_SAMPLES = {};\n".format(len(snare)))
        f.write("const int16_t snare[SNARE_SAMPLES] = {\n    ")
        for i, s in enumerate(snare):
            if i > 0 and i % 8 == 0:
                f.write("\n    ")
            f.write("{:5d}, ".format(s))
        f.write("\n};\n\n")

        f.write("constexpr uint32_t HIHAT_SAMPLES = {};\n".format(len(hihat)))
        f.write("const int16_t hihat[HIHAT_SAMPLES] = {\n    ")
        for i, s in enumerate(hihat):
            if i > 0 and i % 8 == 0:
                f.write("\n    ")
            f.write("{:5d}, ".format(s))
        f.write("\n};\n\n")

        f.write("} // namespace Samples\n\n")
        f.write("#endif // SAMPLES_H\n")

    # Statistics
    for name, data in [("Kick", kick), ("Snare", snare), ("Hihat", hihat)]:
        mn, mx = min(data), max(data)
        duration_ms = len(data) / DST_RATE * 1000
        print(
            f"  {name}: {len(data)} samples ({duration_ms:.1f}ms), range [{mn}, {mx}]"
        )

    total_bytes = (len(kick) + len(snare) + len(hihat)) * 2
    print(f"  Total: {total_bytes} bytes ({total_bytes / 1024:.1f} KB)")


if __name__ == "__main__":
    print("Reading 808 samples from Compulidian...")

    _, kick_raw = parse_c_array(os.path.join(SAMPLES_DIR, "Bd2550.h"))
    _, snare_raw = parse_c_array(os.path.join(SAMPLES_DIR, "Sd0010.h"))
    _, hihat_raw = parse_c_array(os.path.join(SAMPLES_DIR, "Ch.h"))

    print(
        f"  Kick raw: {len(kick_raw)} samples ({len(kick_raw) / SRC_RATE * 1000:.1f}ms)"
    )
    print(
        f"  Snare raw: {len(snare_raw)} samples ({len(snare_raw) / SRC_RATE * 1000:.1f}ms)"
    )
    print(
        f"  Hihat raw: {len(hihat_raw)} samples ({len(hihat_raw) / SRC_RATE * 1000:.1f}ms)"
    )

    print("\nResampling to 48000Hz...")
    kick_48 = resample_linear(kick_raw, SRC_RATE, DST_RATE)
    snare_48 = resample_linear(snare_raw, SRC_RATE, DST_RATE)
    hihat_48 = resample_linear(hihat_raw, SRC_RATE, DST_RATE)

    print("\nTrimming kick to 250ms...")
    kick_48 = trim_samples(kick_48, DST_RATE, KICK_TRIM_MS)

    print("\nScaling to +/-2047 range...")
    kick_out = scale_to_audioout(kick_48)
    snare_out = scale_to_audioout(snare_48)
    hihat_out = scale_to_audioout(hihat_48)

    output_path = os.path.join(os.path.dirname(os.path.abspath(__file__)), "samples.h")
    print(f"\nWriting {output_path}...")
    write_header(kick_out, snare_out, hihat_out, output_path)
    print("\nsamples.h generated successfully!")
